+func restoreGetAPIResourceListFn() func() {
+	orig := getAPIResourceListFn
+	return func() { getAPIResourceListFn = orig }
+}
+
+func enabledMonitoringResources(ctx context.Context, logger logr.Logger, resourceListsFn apiResourceListFunc, cfg allocatorconfig.Config) (map[schema.GroupVersionResource]bool, error) {
+	desired := map[schema.GroupVersionResource]bool{
+		monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.ServiceMonitorName): cfg.PrometheusCR.ServiceMonitorSelector != nil,
+		monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.PodMonitorName):     cfg.PrometheusCR.PodMonitorSelector != nil,
+		monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.ProbeName):          cfg.PrometheusCR.ProbeSelector != nil,
+		promv1alpha1.SchemeGroupVersion.WithResource(promv1alpha1.ScrapeConfigName):   cfg.PrometheusCR.ScrapeConfigSelector != nil,
+	}
+
+	out := make(map[schema.GroupVersionResource]bool, len(desired))
+	for gvr, enabled := range desired {
+		out[gvr] = enabled
+	}
+
+	// If a selector is disabled (nil), we don't need to check CRD presence.
+	resourcesToCheck := make([]schema.GroupVersionResource, 0, len(desired))
+	for gvr, enabled := range desired {
+		if enabled {
+			resourcesToCheck = append(resourcesToCheck, gvr)
+		}
+	}
+	if len(resourcesToCheck) == 0 {
+		return out, nil
 	}

-	scrapeConfigInformers, err := informers.NewInformersForResource(factory, promv1alpha1.SchemeGroupVersion.WithResource(promv1alpha1.ScrapeConfigName))
+	resourceLists, err := resourceListsFn()
 	if err != nil {
-		return nil, err
+		// Partial discovery failures are common; keep whatever we can.
+		if !apierrors.IsNotFound(err) {
+			logger.V(1).Info("Failed to discover monitoring resources; will assume enabled selectors exist", "error", err)
+			return out, nil
+		}
+		// Partial discovery indicates some groups are missing; continue using partial results.
 	}

-	return map[string]*informers.ForResource{
-		monitoringv1.ServiceMonitorName: serviceMonitorInformers,
-		monitoringv1.PodMonitorName:     podMonitorInformers,
-		monitoringv1.ProbeName:          probeInformers,
-		promv1alpha1.ScrapeConfigName:   scrapeConfigInformers,
-	}, nil
+	installed := map[schema.GroupVersionResource]struct{}{}
+	for _, rl := range resourceLists {
+		gv, parseErr := schema.ParseGroupVersion(rl.GroupVersion)
+		if parseErr != nil {
+			continue
+		}
+		for _, r := range rl.APIResources {
+			installed[schema.GroupVersionResource{Group: gv.Group, Version: gv.Version, Resource: r.Name}] = struct{}{}
+		}
+	}
+
+	for _, gvr := range resourcesToCheck {
+		if _, ok := installed[gvr]; !ok {
+			logger.Info("Monitoring resource not found in cluster; disabling", "resource", gvr.Resource, "group", gvr.Group, "version", gvr.Version)
+			out[gvr] = false
+		}
+	}
+
+	return out, nil
 }

