func TestNamespaceLabelUpdate(t *testing.T) {
	defer restoreGetAPIResourceListFn()()

	var err error
	namespace := "test"
	portName := "web"
	podMonitors := []*monitoringv1.PodMonitor{
		{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "pm-1",
