// getInformers returns a map of informers for the given resources.
func getInformers(factory informers.FactoriesForNamespaces, logger logr.Logger, cfg allocatorconfig.Config) (map[string]*informers.ForResource, error) {
	gvrEnabled, err := enabledMonitoringResources(context.Background(), logger, getAPIResourceListFn(factory.Monitoring().Discovery()), cfg)
	if err != nil {
		return nil, err
	}

	resources := map[string]schema.GroupVersionResource{
		monitoringv1.ServiceMonitorName: monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.ServiceMonitorName),
		monitoringv1.PodMonitorName:     monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.PodMonitorName),
		monitoringv1.ProbeName:          monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.ProbeName),
		promv1alpha1.ScrapeConfigName:   promv1alpha1.SchemeGroupVersion.WithResource(promv1alpha1.ScrapeConfigName),
	}

	out := make(map[string]*informers.ForResource)
	for name, gvr := range resources {
		if !gvrEnabled[gvr] {
			logger.V(1).Info("Skipping informer, CRD not installed or selector disabled", "resource", name, "group", gvr.Group, "version", gvr.Version)
			continue
		}
		inf, err := informers.NewInformersForResource(factory, gvr)
		if err != nil {
			return nil, err
		}
		out[name] = inf
	}

	return out, nil
}

