		monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.PodMonitorName):     cfg.PrometheusCR.PodMonitorSelector != nil,
		monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.ProbeName):          cfg.PrometheusCR.ProbeSelector != nil,
		promv1alpha1.SchemeGroupVersion.WithResource(promv1alpha1.ScrapeConfigName):   cfg.PrometheusCR.ScrapeConfigSelector != nil,
	}

	out := make(map[schema.GroupVersionResource]bool, len(desired))
	for gvr, enabled := range desired {
		out[gvr] = enabled
	}

	// If a selector is disabled (nil), we don't need to check CRD presence.
	resourcesToCheck := make([]schema.GroupVersionResource, 0, len(desired))
	for gvr, enabled := range desired {
		if enabled {
			resourcesToCheck = append(resourcesToCheck, gvr)
		}
	}
	if len(resourcesToCheck) == 0 {
		return out, nil
	}

	resourceLists, err := resourceListsFn()
	if err != nil {
		// Partial discovery failures are common; keep whatever we can.
		if !apierrors.IsNotFound(err) {
			logger.V(1).Info("Failed to discover monitoring resources; will assume enabled selectors exist", "error", err)
